import React, { useState } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

// --- HELPER FUNCTIONS ---
const isSameDay = (d1, d2) => d1.toDateString() === d2.toDateString();
const isSameMonth = (d1, d2) => d1.getMonth() === d2.getMonth() && d1.getFullYear() === d2.getFullYear();
const isSameWeek = (d1, d2) => {
    const start = new Date(d2);
    start.setHours(0,0,0,0);
    start.setDate(start.getDate() - start.getDay() + 1); 
    const end = new Date(start);
    end.setDate(end.getDate() + 6);
    return d1 >= start && d1 <= end;
};

// --- ICONS ---
const Icons = {
    Task: () => (<svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="1.5"><path strokeLinecap="round" strokeLinejoin="round" d="M9 12h3.75M9 15h3.75M9 18h3.75m3 .75H18a2.25 2.25 0 002.25-2.25V6.108c0-1.135-.845-2.098-1.976-2.192a48.424 48.424 0 00-1.123-.08m-5.801 0c-.065.21-.1.433-.1.664 0 .414.336.75.75.75h4.5a.75.75 0 00.75-.75 2.25 2.25 0 00-.1-.664m-5.8 0A2.251 2.251 0 0113.5 2.25H15c1.012 0 1.867.668 2.15 1.586m-5.8 0c-.376.023-.75.05-1.124.08C9.095 4.01 8.25 4.973 8.25 6.108V8.25m0 0H4.875c-.621 0-1.125.504-1.125 1.125v11.25c0 .621.504 1.125 1.125 1.125h9.75c.621 0 1.125-.504 1.125-1.125V9.375c0-.621-.504-1.125-1.125-1.125H8.25zM6.75 12h.008v.008H6.75V12zm0 3h.008v.008H6.75V15zm0 3h.008v.008H6.75V18z" /></svg>),
    Schedule: () => (<svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="1.5"><path strokeLinecap="round" strokeLinejoin="round" d="M6.75 3v2.25M17.25 3v2.25M3 18.75V7.5a2.25 2.25 0 012.25-2.25h13.5A2.25 2.25 0 0121 7.5v11.25m-18 0A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75m-18 0v-7.5A2.25 2.25 0 015.25 9h13.5A2.25 2.25 0 0121 11.25v7.5" /></svg>),
    ArrowRight: () => (<svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2"><path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" /></svg>),
    Back: () => (<svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2"><path strokeLinecap="round" strokeLinejoin="round" d="M10.5 19.5L3 12m0 0l7.5-7.5M3 12h18" /></svg>),
    AddCircle: () => (<svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="1.5"><path strokeLinecap="round" strokeLinejoin="round" d="M12 9v6m3-3H9m12 0a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>),
    ListCheck: () => (<svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="1.5"><path strokeLinecap="round" strokeLinejoin="round" d="M8.25 6.75h12M8.25 12h12m-12 5.25h12M3.75 6.75h.007v.008H3.75V6.75zm.375 0a.375.375 0 11-.75 0 .375.375 0 01.75 0zM3.75 12h.007v.008H3.75V12zm.375 0a.375.375 0 11-.75 0 .375.375 0 01.75 0zm-.375 5.25h.007v.008H3.75v-.008zm.375 0a.375.375 0 11-.75 0 .375.375 0 01.75 0z" /></svg>)
};

const TaskManager = () => {
  const { user } = useAuth();
  const { tasks, addTask, deleteTask, staffList, disciplineTypes, schedules, addSchedule, deleteSchedule, updateSchedule } = useData();
  
  const activeDisciplines = disciplineTypes.filter(d => d.status === 'Active');
  
  // --- PHÂN QUYỀN ---
  const isScheduler = user?.role === 'scheduler';
  const isApprover = ['chief', 'reg', 'op'].includes(user?.role);

  // --- THẺ CON (SUB-TABS CHO ADMIN) ---
  const [activeView, setActiveView] = useState('overview'); // overview, assignTask, assignSchedule, manageTasks, manageSchedules

  // --- STATE FORM: MỤC 1 (TASK LẺ) ---
  const [singleTask, setSingleTask] = useState({ 
      title: '', assigneeId: '', description: '',
      startTime: '', endTime: '', 
      assignedRole: 'ST',
      paymentAmount: '', // Thay đổi: input nhập mức tiền thay vì dropdown
      disciplineId: ''
  });

  // --- STATE FORM: MỤC 2 (SCHEDULE) ---
  const [scheduleTask, setScheduleTask] = useState({
      title: '', assigneeId: '', description: '',
      startTime: '', endTime: '', assignedRole: 'ST',
  });
  const [scheduleConfig, setScheduleConfig] = useState({ repeatWeeks: 1, days: [] });
  const [editingScheduleId, setEditingScheduleId] = useState(null);

  // --- BỘ LỌC DỮ LIỆU ---
  const [filterStaff, setFilterStaff] = useState('all');
  const [filterDay, setFilterDay] = useState('all');
  const [filterTaskTime, setFilterTaskTime] = useState('all'); 
  const [scheduleSearchTerm, setScheduleSearchTerm] = useState('');

  const daysOfWeek = [
      { key: 'Mon', label: 'T2', val: 1 }, { key: 'Tue', label: 'T3', val: 2 }, { key: 'Wed', label: 'T4', val: 3 },
      { key: 'Thu', label: 'T5', val: 4 }, { key: 'Fri', label: 'T6', val: 5 }, { key: 'Sat', label: 'T7', val: 6 },
      { key: 'Sun', label: 'CN', val: 0 }
  ];

  // --- HELPER FORMAT TIME ---
  const formatTaskTime = (start, end) => {
      const s = new Date(start);
      const e = new Date(end);
      return (
          <div>
              <div style={{fontWeight:'bold', fontSize:'0.85rem'}}>{s.toLocaleDateString('vi-VN')}</div>
              <div style={{fontSize:'0.8rem', color:'#6b7280'}}>
                  {s.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})} - {e.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}
              </div>
          </div>
      );
  };

  const formatScheduleTimeRange = (start, end) => {
      const s = new Date(start);
      const e = new Date(end);
      return `${s.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})} - ${e.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}`;
  };

  // --- LOGIC FUNCTIONS ---
  
  // Hàm tạo tasks con từ 1 lịch gốc (Lọc bỏ các ngày trong quá khứ nếu là update)
  const generateTasksFromSchedule = (scheduleData, schedId, isUpdate = false) => {
    const { startTime, endTime, repeatWeeks, repeatDays } = scheduleData;
    const startObj = new Date(startTime);
    const endObj = new Date(endTime);
    const duration = endObj - startObj;
    const now = new Date();

    const targetDayVals = daysOfWeek.filter(d => repeatDays.includes(d.key)).map(d => d.val);

    for (let w = 0; w < repeatWeeks; w++) {
        for (let d = 0; d < 7; d++) {
            const currentCheckDate = new Date(startObj);
            currentCheckDate.setDate(startObj.getDate() + (w * 7) + d);

            if (targetDayVals.includes(currentCheckDate.getDay())) {
                const taskStart = new Date(currentCheckDate);
                const taskEnd = new Date(taskStart.getTime() + duration);

                // Nếu là update, chỉ sinh ra các task ở tương lai
                if (isUpdate && taskStart < now) continue;

                const taskPayload = {
                    title: scheduleData.title,
                    assigneeId: scheduleData.assigneeId,
                    assigneeName: scheduleData.assigneeName,
                    description: scheduleData.description,
                    assignedRole: scheduleData.assignedRole,
                    startTime: taskStart.toISOString(),
                    endTime: taskEnd.toISOString(),
                    paymentType: 'Theo lịch', 
                    disciplineId: '', 
                    disciplineName: '',
                    deadline: taskEnd.toISOString(),
                    fromScheduleId: schedId,
                    generatedDate: new Date().toISOString()
                };
                addTask(taskPayload);
            }
        }
    }
  };

  // Xóa task an toàn (Không xóa những task đã làm/đang làm để bảo toàn báo cáo)
  const safeDeleteRelatedTasks = (schedId) => {
      const relatedTasks = tasks.filter(t => t.fromScheduleId === schedId);
      relatedTasks.forEach(t => {
          // Chỉ xóa những task có progress = 0 (hoặc undefined) 
          // Nghĩa là nhân viên chưa bắt đầu làm (bảo toàn số giờ)
          if (!t.progress || t.progress === 0) {
              deleteTask(t.id);
          }
      });
  };

  // Xóa toàn bộ task khi Admin muốn xóa hẳn 1 lịch gốc
  const forceDeleteAllRelatedTasks = (schedId) => {
      const relatedTasks = tasks.filter(t => t.fromScheduleId === schedId);
      relatedTasks.forEach(t => deleteTask(t.id));
  };

  // --- SUBMIT HANDLERS ---

  // Xử lý nộp MỤC 1: Giao Task Lẻ
  const handleAssignSingleTask = (e) => {
      e.preventDefault();
      if (!singleTask.title || !singleTask.assigneeId || !singleTask.endTime) return alert("Vui lòng điền đủ thông tin!");
      
      const staff = staffList.find(s => s.id === singleTask.assigneeId);
      const disc = activeDisciplines.find(d => d.id === singleTask.disciplineId);
      
      addTask({ 
          ...singleTask, 
          paymentType: singleTask.paymentAmount ? `Mức chi trả: ${singleTask.paymentAmount}` : 'Không xác định',
          assigneeName: staff ? staff.name : 'Unknown',
          disciplineName: disc ? disc.name : 'Chưa quy định',
          deadline: singleTask.endTime
      });
      
      setSingleTask({ title: '', assigneeId: '', description: '', startTime: '', endTime: '', assignedRole: 'ST', paymentAmount: '', disciplineId: '' });
      alert("Đã giao nhiệm vụ thành công!");
      setActiveView('overview'); // Quay về màn hình thẻ
  };

  // Xử lý nộp MỤC 2 (Hoặc Scheduler form): Lên lịch định kỳ
  const handleAssignSchedule = (e) => {
      e.preventDefault();
      if (!scheduleTask.title || !scheduleTask.assigneeId || !scheduleTask.endTime) return alert("Vui lòng điền đủ thông tin!");
      if (scheduleConfig.days.length === 0) return alert("Vui lòng chọn ít nhất một ngày trong tuần!");
      
      const staff = staffList.find(s => s.id === scheduleTask.assigneeId);
      const scheduleData = {
          ...scheduleTask,
          assigneeName: staff ? staff.name : 'Unknown',
          repeatWeeks: Number(scheduleConfig.repeatWeeks),
          repeatDays: scheduleConfig.days,
          createdBy: user.username
      };

      if (editingScheduleId) {
          if (isScheduler) {
              // Scheduler chỉ được gửi yêu cầu
              updateSchedule(editingScheduleId, {
                  request: { type: 'edit', reason: 'Điều chỉnh thông tin', draftData: scheduleData, requestedBy: user.username, requestedAt: new Date().toISOString() }
              });
              alert("Đã gửi yêu cầu điều chỉnh. Admin sẽ xem xét và phê duyệt.");
          } else {
              // Admin Sửa trực tiếp
              updateSchedule(editingScheduleId, scheduleData);
              safeDeleteRelatedTasks(editingScheduleId); // Xóa task tương lai
              generateTasksFromSchedule(scheduleData, editingScheduleId, true); // Tạo task tương lai mới
              alert("Đã cập nhật lịch trình thành công (Không làm mất dữ liệu task quá khứ)!");
              setActiveView('manageSchedules');
          }
      } else {
          // Tạo mới
          const savedId = addSchedule(scheduleData);
          generateTasksFromSchedule(scheduleData, savedId);
          alert(`Đã lên lịch và tạo chuỗi công việc cho ${scheduleData.assigneeName}!`);
          if(!isScheduler) setActiveView('overview');
      }

      setScheduleTask({ title: '', assigneeId: '', description: '', startTime: '', endTime: '', assignedRole: 'ST' });
      setScheduleConfig({ repeatWeeks: 1, days: [] });
      setEditingScheduleId(null);
  };

  const handleEditScheduleClick = (sched) => {
      setEditingScheduleId(sched.id);
      setScheduleTask({
          title: sched.title, assigneeId: sched.assigneeId, description: sched.description,
          startTime: sched.startTime, endTime: sched.endTime, assignedRole: sched.assignedRole
      });
      setScheduleConfig({ repeatWeeks: sched.repeatWeeks, days: sched.repeatDays || [] });
      if(!isScheduler) setActiveView('assignSchedule');
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleDeleteScheduleClick = (id) => {
      if(window.confirm("CẢNH BÁO: Xóa lịch này sẽ xóa cả các nhiệm vụ tương lai liên quan. Tiếp tục?")) {
          forceDeleteAllRelatedTasks(id); // Admin có quyền xóa sạch
          deleteSchedule(id);
      }
  };

  const handleDayToggle = (dayKey) => {
      setScheduleConfig(prev => {
          const exists = prev.days.includes(dayKey);
          return { ...prev, days: exists ? prev.days.filter(d => d !== dayKey) : [...prev.days, dayKey] };
      });
  };

  // Logic Scheduler gửi duyệt
  const handleApproveRequest = (sched) => {
      const { request } = sched;
      if (!request) return;
      if (window.confirm(`Xác nhận phê duyệt yêu cầu "${request.type}"?`)) {
          if (request.type === 'delete') {
              forceDeleteAllRelatedTasks(sched.id);
              deleteSchedule(sched.id);
          } else if (request.type === 'edit') {
              const newScheduleData = { ...request.draftData, request: null };
              updateSchedule(sched.id, newScheduleData);
              safeDeleteRelatedTasks(sched.id);
              generateTasksFromSchedule(newScheduleData, sched.id, true);
          }
      }
  };

  const handleRejectRequest = (sched) => {
      const reason = window.prompt("Lý do từ chối (tùy chọn):");
      if (window.confirm("Từ chối yêu cầu này?")) updateSchedule(sched.id, { request: null, rejectionReason: reason || '' });
  };

  // --- LỌC DỮ LIỆU ---
  
  // Dành cho Mục 3 (Task lẻ)
  const singleTasksList = tasks.filter(t => {
      if(t.fromScheduleId) return false; // Chỉ lấy task lẻ (Mục 1)
      const date = new Date(t.startTime);
      const now = new Date();
      const matchStaff = filterStaff === 'all' || t.assigneeId === filterStaff;
      let matchDay = true;
      if (filterDay !== 'all') matchDay = date.getDay() === daysOfWeek.find(d => d.key === filterDay)?.val;
      let matchTime = true;
      if (filterTaskTime === 'day') matchTime = isSameDay(date, now);
      else if (filterTaskTime === 'week') matchTime = isSameWeek(date, now);
      else if (filterTaskTime === 'month') matchTime = isSameMonth(date, now);
      return matchStaff && matchDay && matchTime;
  });

  // Dành cho Mục 4 (Scheduled tasks)
  const scheduledTasksList = tasks.filter(t => {
      if(!t.fromScheduleId) return false; // Chỉ lấy task sinh từ lịch (Mục 2)
      const date = new Date(t.startTime);
      const matchStaff = filterStaff === 'all' || t.assigneeId === filterStaff;
      let matchDay = true;
      if (filterDay !== 'all') matchDay = date.getDay() === daysOfWeek.find(d => d.key === filterDay)?.val;
      return matchStaff && matchDay;
  });

  const searchedSchedules = schedules.filter(s => {
      if (!scheduleSearchTerm.trim()) return true;
      const term = scheduleSearchTerm.toLowerCase();
      return (s.title && s.title.toLowerCase().includes(term)) || (s.assigneeName && s.assigneeName.toLowerCase().includes(term));
  });

  // ================= RENDER COMPONENTS =================

  // COMPONENT: FORM TASK LẺ (MỤC 1)
  const AssignTaskForm = () => (
      <div style={styles.formContainer}>
          <div style={styles.formHeader}>
             <h4 style={{ margin: 0, color: '#003366', fontWeight: '600' }}>Mục 1: Giao nhiệm vụ (TASK+) & Kỷ luật</h4>
             <button onClick={() => setActiveView('overview')} style={styles.backBtn}><Icons.Back /> Ẩn thẻ</button>
          </div>
          <form onSubmit={handleAssignSingleTask} style={styles.gridForm}>
              <div style={{ gridColumn: '1 / -1' }}>
                 <label style={styles.label}>Tiêu đề công việc</label>
                 <input value={singleTask.title} onChange={e => setSingleTask({...singleTask, title: e.target.value})} style={styles.input} required />
              </div>
              <div>
                 <label style={styles.label}>Người thực hiện</label>
                 <select value={singleTask.assigneeId} onChange={e => setSingleTask({...singleTask, assigneeId: e.target.value})} style={styles.select} required>
                    <option value="">-- Chọn nhân sự --</option>
                    {staffList.map(s => <option key={s.id} value={s.id}>{s.name} ({s.role})</option>)}
                 </select>
              </div>
              <div>
                 <label style={styles.label}>Vai trò thực hiện</label>
                 <select value={singleTask.assignedRole} onChange={e => setSingleTask({...singleTask, assignedRole: e.target.value})} style={styles.select}>
                    {['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r => <option key={r} value={r}>{r}</option>)}
                 </select>
              </div>
              <div>
                 <label style={styles.label}>Bắt đầu (Check-in)</label>
                 <input type="datetime-local" value={singleTask.startTime} onChange={e => setSingleTask({...singleTask, startTime: e.target.value})} style={styles.input} required />
              </div>
              <div>
                 <label style={styles.label}>Kết thúc (Check-out)</label>
                 <input type="datetime-local" value={singleTask.endTime} onChange={e => setSingleTask({...singleTask, endTime: e.target.value})} style={styles.input} required />
              </div>
              <div>
                 <label style={styles.label}>Mức tiền chi trả</label>
                 <input type="text" placeholder="Nhập mức chi trả (VD: 50,000 VNĐ)" value={singleTask.paymentAmount} onChange={e => setSingleTask({...singleTask, paymentAmount: e.target.value})} style={styles.input} />
              </div>
              <div>
                 <label style={styles.label}>Kỷ luật (nếu trễ)</label>
                 <select value={singleTask.disciplineId} onChange={e => setSingleTask({...singleTask, disciplineId: e.target.value})} style={{...styles.select, borderColor: 'red', color: '#b91c1c'}}>
                    <option value="">-- Chọn hình thức --</option>
                    {activeDisciplines.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}
                 </select>
              </div>
              <div style={{ gridColumn: '1 / -1' }}>
                 <label style={styles.label}>Mô tả chi tiết</label>
                 <textarea value={singleTask.description} onChange={e => setSingleTask({...singleTask, description: e.target.value})} style={{...styles.input, height: '80px'}} />
              </div>
              <button type="submit" style={styles.btnSubmit}>Xác nhận giao việc</button>
          </form>
      </div>
  );

  // COMPONENT: FORM LỊCH ĐỊNH KỲ (MỤC 2 & SCHEDULER)
  const AssignScheduleForm = () => (
      <div style={styles.formContainer}>
          <div style={styles.formHeader}>
             <h4 style={{ margin: 0, color: '#003366', fontWeight: '600' }}>
                 {!isScheduler ? 'Mục 2: Lên lịch công tác định kỳ' : (editingScheduleId ? 'Sửa yêu cầu lịch trình' : 'Lên lịch công tác mới')}
             </h4>
             {!isScheduler && <button onClick={() => {setActiveView('overview'); setEditingScheduleId(null)}} style={styles.backBtn}><Icons.Back /> Ẩn thẻ</button>}
          </div>
          <form onSubmit={handleAssignSchedule} style={styles.gridForm}>
              <div style={{ gridColumn: '1 / -1' }}>
                 <label style={styles.label}>Tiêu đề lịch trình</label>
                 <input value={scheduleTask.title} onChange={e => setScheduleTask({...scheduleTask, title: e.target.value})} style={styles.input} required />
              </div>
              <div>
                 <label style={styles.label}>Người thực hiện</label>
                 <select value={scheduleTask.assigneeId} onChange={e => setScheduleTask({...scheduleTask, assigneeId: e.target.value})} style={styles.select} required>
                    <option value="">-- Chọn nhân sự --</option>
                    {staffList.map(s => <option key={s.id} value={s.id}>{s.name} ({s.role})</option>)}
                 </select>
              </div>
              <div>
                 <label style={styles.label}>Vai trò thực hiện</label>
                 <select value={scheduleTask.assignedRole} onChange={e => setScheduleTask({...scheduleTask, assignedRole: e.target.value})} style={styles.select}>
                    {['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r => <option key={r} value={r}>{r}</option>)}
                 </select>
              </div>
              <div>
                 <label style={styles.label}>Khung giờ Bắt đầu</label>
                 <input type="datetime-local" value={scheduleTask.startTime} onChange={e => setScheduleTask({...scheduleTask, startTime: e.target.value})} style={styles.input} required />
              </div>
              <div>
                 <label style={styles.label}>Khung giờ Kết thúc</label>
                 <input type="datetime-local" value={scheduleTask.endTime} onChange={e => setScheduleTask({...scheduleTask, endTime: e.target.value})} style={styles.input} required />
              </div>
              
              <div style={{ gridColumn: '1 / -1', background: '#f9fafb', padding: '15px', borderRadius: '8px', border: '1px solid #e5e7eb' }}>
                 <h5 style={{margin:'0 0 10px 0', fontSize:'0.9rem', color:'#003366'}}>Cấu hình chu kỳ lặp lại</h5>
                 <div style={{display:'flex', alignItems:'center', gap:'20px', flexWrap:'wrap'}}>
                     <div style={{display:'flex', flexDirection:'column'}}>
                         <label style={styles.label}>Số tuần lặp lại:</label>
                         <input type="number" min="1" max="52" value={scheduleConfig.repeatWeeks} onChange={e => setScheduleConfig({...scheduleConfig, repeatWeeks: e.target.value})} style={{...styles.input, width: '100px'}} />
                     </div>
                     <div style={{display:'flex', flexDirection:'column'}}>
                         <label style={styles.label}>Chọn thứ trong tuần:</label>
                         <div style={{display:'flex', gap:'8px', marginTop:'5px', flexWrap: 'wrap'}}>
                             {daysOfWeek.map(d => (
                                 <div key={d.key} onClick={() => handleDayToggle(d.key)} style={{ width:'32px', height:'32px', borderRadius:'50%', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'0.8rem', cursor:'pointer', fontWeight:'bold', border: '1px solid #d1d5db', background: scheduleConfig.days.includes(d.key) ? '#003366' : 'white', color: scheduleConfig.days.includes(d.key) ? 'white' : '#6b7280' }}>
                                     {d.label}
                                 </div>
                             ))}
                         </div>
                     </div>
                 </div>
              </div>

              <div style={{ gridColumn: '1 / -1' }}>
                 <label style={styles.label}>Mô tả chi tiết</label>
                 <textarea value={scheduleTask.description} onChange={e => setScheduleTask({...scheduleTask, description: e.target.value})} style={{...styles.input, height: '80px'}} />
              </div>
              <button type="submit" style={styles.btnSubmit}>{editingScheduleId ? 'Cập nhật lịch trình' : 'Lưu & Sinh chuỗi công việc'}</button>
          </form>
      </div>
  );

  return (
    <div style={{ paddingBottom: '20px' }}>
      <h2 style={{ color: '#003366', borderBottom: '2px solid #e5e7eb', paddingBottom: '15px', marginBottom: '20px', fontWeight: 'bold', fontSize: '1.5rem' }}>
          {isScheduler ? 'LÊN LỊCH CÔNG TÁC (SCHEDULER)' : 'QUẢN LÝ NHIỆM VỤ - OPERATIONS'}
      </h2>

      {/* DUYỆT YÊU CẦU (OP/CHIEF) */}
      {isApprover && schedules.some(s => s.request) && (
          <div style={{ background: '#fff7ed', padding: '20px', borderRadius: '16px', border: '1px solid #fed7aa', marginBottom: '24px' }}>
              <h4 style={{ color: '#c2410c', marginTop: 0 }}>⚠️ Yêu cầu điều chỉnh từ Scheduler</h4>
              <table style={{ width: '100%', fontSize: '0.9rem', borderCollapse: 'collapse', minWidth: '600px' }}>
                 <thead><tr style={{ textAlign: 'left', color: '#9a3412' }}><th>Lịch trình</th><th>Loại</th><th>Hành động</th></tr></thead>
                 <tbody>
                    {schedules.filter(s => s.request).map(s => (
                        <tr key={s.id} style={{ borderTop: '1px solid #ffedd5' }}>
                            <td style={{padding: '8px'}}>{s.title}</td>
                            <td><span style={{ padding: '2px 8px', borderRadius: '4px', background: '#dbeafe', color: '#1e40af' }}>{s.request.type}</span></td>
                            <td>
                                <button onClick={() => handleApproveRequest(s)} style={{ marginRight: '8px', background: '#16a34a', color: 'white', border: 'none', padding: '4px 10px', borderRadius: '4px' }}>Duyệt</button>
                                <button onClick={() => handleRejectRequest(s)} style={{ background: '#dc2626', color: 'white', border: 'none', padding: '4px 10px', borderRadius: '4px' }}>Từ chối</button>
                            </td>
                        </tr>
                    ))}
                 </tbody>
              </table>
          </div>
      )}

      {/* GIAO DIỆN SCHEDULER (GIỮ NGUYÊN DO YÊU CẦU CHỈ ĐỔI GIAO DIỆN ADMIN) */}
      {isScheduler && (
          <>
             <AssignScheduleForm />
             {/* Bảng của Scheduler ở dưới này... (Lấy theo code cũ) */}
          </>
      )}

      {/* GIAO DIỆN ADMIN: 4 THẺ */}
      {!isScheduler && (
          <>
             {/* MENU 4 THẺ TỔNG QUAN */}
             {activeView === 'overview' && (
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '20px' }}>
                    <div style={styles.menuCard}>
                        <div style={styles.cardHeader}><div style={styles.iconBox}><Icons.AddCircle /></div><h3 style={styles.cardTitle}>Mục 1. Giao nhiệm vụ lẻ</h3></div>
                        <div style={styles.cardDesc}>Tạo task lẻ, thiết lập kỷ luật và mức tiền chi trả (nhập thủ công).</div>
                        <button onClick={() => setActiveView('assignTask')} style={styles.accessBtn}>Truy cập <Icons.ArrowRight /></button>
                    </div>

                    <div style={styles.menuCard}>
                        <div style={styles.cardHeader}><div style={styles.iconBox}><Icons.Schedule /></div><h3 style={styles.cardTitle}>Mục 2. Lên lịch định kỳ</h3></div>
                        <div style={styles.cardDesc}>Khởi tạo lịch công tác tuần hoàn tương tự công cụ của Scheduler.</div>
                        <button onClick={() => setActiveView('assignSchedule')} style={styles.accessBtn}>Truy cập <Icons.ArrowRight /></button>
                    </div>

                    <div style={styles.menuCard}>
                        <div style={styles.cardHeader}><div style={styles.iconBox}><Icons.Task /></div><h3 style={styles.cardTitle}>Mục 3. Quản lý Task lẻ</h3></div>
                        <div style={styles.cardDesc}>Theo dõi tiến độ và quản lý các công việc đã thiết lập ở Mục 1.</div>
                        <button onClick={() => setActiveView('manageTasks')} style={styles.accessBtn}>Truy cập <Icons.ArrowRight /></button>
                    </div>

                    <div style={styles.menuCard}>
                        <div style={styles.cardHeader}><div style={styles.iconBox}><Icons.ListCheck /></div><h3 style={styles.cardTitle}>Mục 4. Quản lý Lịch & Chuỗi Task</h3></div>
                        <div style={styles.cardDesc}>Gộp quản lý Lịch gốc và danh sách chuỗi nhiệm vụ định kỳ đang diễn ra.</div>
                        <button onClick={() => setActiveView('manageSchedules')} style={styles.accessBtn}>Truy cập <Icons.ArrowRight /></button>
                    </div>
                </div>
             )}

             {/* RENDER CÁC MÀN HÌNH TƯƠNG ỨNG KHI ĐƯỢC CHỌN */}
             {activeView === 'assignTask' && <AssignTaskForm />}
             {activeView === 'assignSchedule' && <AssignScheduleForm />}

             {/* MỤC 3: QUẢN LÝ NHIỆM VỤ LẺ */}
             {activeView === 'manageTasks' && (
                 <div style={styles.viewContainer}>
                     <div style={styles.formHeader}>
                        <h4 style={{ margin: 0, color: '#003366', fontSize: '1.2rem' }}>Mục 3: Tiến độ Nhiệm vụ lẻ (Từ Mục 1)</h4>
                        <button onClick={() => setActiveView('overview')} style={styles.backBtn}><Icons.Back /> Ẩn thẻ</button>
                     </div>
                     <div style={{display:'flex', gap:'10px', flexWrap:'wrap', marginBottom:'15px'}}>
                         <select value={filterStaff} onChange={e => setFilterStaff(e.target.value)} style={styles.filterSelect}><option value="all">Tất cả nhân sự</option>{staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}</select>
                         <select value={filterDay} onChange={e => setFilterDay(e.target.value)} style={styles.filterSelect}><option value="all">Tất cả các ngày</option>{daysOfWeek.map(d => <option key={d.key} value={d.key}>{d.label}</option>)}</select>
                         <select value={filterTaskTime} onChange={e => setFilterTaskTime(e.target.value)} style={styles.filterSelect}><option value="all">Tất cả thời gian</option><option value="day">Hôm nay</option><option value="week">Tuần này</option><option value="month">Tháng này</option></select>
                     </div>
                     <table style={styles.table}>
                        <thead><tr><th>STT</th><th>Nhiệm vụ</th><th>Người làm</th><th>Vai trò</th><th>Thời gian</th><th>Tiến độ</th><th>Xóa</th></tr></thead>
                        <tbody>
                           {singleTasksList.map((t, index) => (
                             <tr key={t.id}>
                                <td>{index + 1}</td>
                                <td><strong>{t.title}</strong><br/><span style={{fontSize:'0.75rem', color:'#666'}}>{t.paymentType}</span></td>
                                <td>{t.assigneeName}</td><td>{t.assignedRole}</td>
                                <td>{formatTaskTime(t.startTime, t.endTime)}</td>
                                <td>{t.progress}%</td>
                                <td><button onClick={()=>deleteTask(t.id)} style={styles.deleteBtn}>Xóa</button></td>
                             </tr>
                           ))}
                           {singleTasksList.length === 0 && <tr><td colSpan="7" style={{textAlign:'center', padding: '20px'}}>Không có dữ liệu</td></tr>}
                        </tbody>
                     </table>
                 </div>
             )}

             {/* MỤC 4: QUẢN LÝ LỊCH GỐC & CHUỖI TASK */}
             {activeView === 'manageSchedules' && (
                 <div style={styles.viewContainer}>
                    <div style={styles.formHeader}>
                        <h4 style={{ margin: 0, color: '#003366', fontSize: '1.2rem' }}>Mục 4: Quản lý Lịch gốc & Công tác định kỳ</h4>
                        <button onClick={() => setActiveView('overview')} style={styles.backBtn}><Icons.Back /> Ẩn thẻ</button>
                    </div>

                    {/* BẢNG 1: LỊCH GỐC */}
                    <h5 style={{color:'#c2410c', borderBottom:'1px solid #eee', paddingBottom:'10px'}}>A. Lịch gốc định kỳ (Cập nhật lịch sẽ không làm mất giờ đã lưu)</h5>
                    <input type="text" placeholder="Tìm kiếm theo tiêu đề lịch hoặc nhân sự..." value={scheduleSearchTerm} onChange={(e) => setScheduleSearchTerm(e.target.value)} style={{...styles.input, width: '100%', maxWidth: '400px', marginBottom: '15px'}} />
                    <div style={{overflowX: 'auto', marginBottom: '30px'}}>
                        <table style={styles.table}>
                          <thead><tr><th>STT</th><th>Thông tin lịch trình</th><th>Chu kỳ lặp</th><th>Hành động</th></tr></thead>
                          <tbody>
                             {searchedSchedules.map((s, index) => (
                               <tr key={s.id}>
                                  <td>{index + 1}</td>
                                  <td><strong>{s.title}</strong> <br/><span style={{fontSize:'0.8rem', color:'#6b7280'}}>Phụ trách: {s.assigneeName} - Giờ: {formatScheduleTimeRange(s.startTime, s.endTime)}</span></td>
                                  <td>{s.repeatWeeks} tuần | Các ngày: {s.repeatDays?.join(', ')}</td>
                                  <td>
                                      <button onClick={()=>handleEditScheduleClick(s)} style={{...styles.actionBtn, borderColor:'#003366', color:'#003366', marginRight: '8px'}}>Sửa trực tiếp</button>
                                      <button onClick={()=>handleDeleteScheduleClick(s.id)} style={{...styles.actionBtn, background:'#fef2f2', color:'#dc2626'}}>Xóa sạch</button>
                                  </td>
                               </tr>
                             ))}
                          </tbody>
                        </table>
                    </div>

                    {/* BẢNG 2: TIẾN ĐỘ CHUỖI NHIỆM VỤ */}
                    <h5 style={{color:'#16a34a', borderBottom:'1px solid #eee', paddingBottom:'10px'}}>B. Tiến độ các nhiệm vụ sinh ra từ lịch gốc</h5>
                    <div style={{display:'flex', gap:'10px', flexWrap:'wrap', marginBottom:'15px'}}>
                         <select value={filterStaff} onChange={e => setFilterStaff(e.target.value)} style={styles.filterSelect}><option value="all">Tất cả nhân sự</option>{staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}</select>
                         <select value={filterDay} onChange={e => setFilterDay(e.target.value)} style={styles.filterSelect}><option value="all">Tất cả các ngày</option>{daysOfWeek.map(d => <option key={d.key} value={d.key}>{d.label}</option>)}</select>
                     </div>
                    <div style={{overflowX: 'auto'}}>
                         <table style={styles.table}>
                            <thead><tr><th>Ngày làm</th><th>Nhiệm vụ</th><th>Người làm</th><th>Tiến độ</th><th>Xóa cá biệt</th></tr></thead>
                            <tbody>
                               {scheduledTasksList.map(t => (
                                 <tr key={t.id}>
                                    <td>{new Date(t.startTime).toLocaleDateString('vi-VN')}</td>
                                    <td><strong>{t.title}</strong></td>
                                    <td>{t.assigneeName} ({t.assignedRole})</td>
                                    <td>{t.progress}%</td>
                                    <td><button onClick={()=>deleteTask(t.id)} style={styles.deleteBtn}>Xóa task này</button></td>
                                 </tr>
                               ))}
                            </tbody>
                         </table>
                    </div>
                 </div>
             )}
          </>
      )}
    </div>
  );
};

const styles = {
    formContainer: { background: '#fff', padding: '20px', borderRadius: '12px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)', marginBottom: '25px', border: '1px solid #f0f0f0' },
    viewContainer: { background: 'white', padding: '20px', borderRadius: '16px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)', border: '1px solid #e5e7eb' },
    formHeader: { display:'flex', justifyContent:'space-between', alignItems:'center', flexWrap:'wrap', gap:'10px', marginBottom:'20px', borderBottom: '1px solid #eee', paddingBottom: '15px' },
    gridForm: { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '16px' },
    input: { width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #ccc', marginTop: '5px', boxSizing: 'border-box' },
    select: { width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #ccc', marginTop: '5px', background: 'white' },
    filterSelect: { padding: '6px 12px', borderRadius: '6px', border: '1px solid #d1d5db', outline: 'none', color: '#374151', cursor: 'pointer', background:'white' },
    label: { fontSize: '0.8rem', fontWeight: 'bold', color: '#555' },
    btnSubmit: { gridColumn: '1 / -1', padding: '12px', background: '#003366', color: 'white', border: 'none', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer' },
    
    // Cards layout
    menuCard: { background: 'white', borderRadius: '12px', padding: '20px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', border: '1px solid #e5e7eb', display: 'flex', flexDirection: 'column', justifyContent: 'space-between', minHeight: '180px' },
    cardHeader: { display:'flex', alignItems:'center', gap:'12px', marginBottom:'10px' },
    iconBox: { width: '36px', height: '36px', background: '#e0f2fe', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#003366' },
    cardTitle: { margin: 0, fontSize: '1.05rem', fontWeight: '700', color: '#1f2937' },
    cardDesc: { color:'#6b7280', fontSize:'0.85rem', marginBottom:'20px', lineHeight: '1.4' },
    accessBtn: { marginTop: 'auto', background: '#003366', color: 'white', border: 'none', padding: '10px 16px', borderRadius: '8px', cursor: 'pointer', fontWeight: '600', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px' },
    backBtn: { background: '#fef2f2', color: '#ef4444', border: '1px solid #fecaca', padding: '6px 12px', borderRadius: '8px', cursor: 'pointer', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '6px' },
    
    // Table
    table: { width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem', minWidth: '600px', textAlign: 'left' },
    actionBtn: { padding: '4px 10px', borderRadius: '6px', cursor: 'pointer', fontWeight: '600', border: '1px solid', background: 'white' },
    deleteBtn: { color:'red', border:'none', background:'none', cursor:'pointer', fontWeight: '600', textDecoration: 'underline' }
};

export default TaskManager;
